// SettingsFragment.kt
fun onDarkModeToggled(enabled: Boolean) {
    AppCompatDelegate.setDefaultNightMode(
        if (enabled) AppCompatDelegate.MODE_NIGHT_YES
        else AppCompatDelegate.MODE_NIGHT_NO
    )
    // Activity auto-recreates to apply the new mode
}

